	assert.Contains(t, err.Error(), "limited")
	assert.Contains(t, err.Error(), "current=2")
	assert.Contains(t, err.Error(), "max=2")
}

func TestRunMethod(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResourceWithChannel{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 3)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Create test policies
	cnp1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-1",
			Namespace: "default",
		},
	}

	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
	}

	// Send events to the mock resource
	done1 := make(chan error, 1)
	done2 := make(chan error, 1)
	doneSync := make(chan error, 1)

	go func() {
		// Send events with a small delay
		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind:   resource.Upsert,
			Object: cnp1,
			Key:    resource.Key{Name: cnp1.Name, Namespace: cnp1.Namespace},
			Done: func(err error) {
				done1 <- err
			},
		}

		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind:   resource.Upsert,
			Object: cnp2,
			Key:    resource.Key{Name: cnp2.Name, Namespace: cnp2.Namespace},
			Done: func(err error) {
				done2 <- err
			},
		}

		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind: resource.Sync,
			Done: func(err error) {
				doneSync <- err
			},
		}

		// Give time for processing then cancel context
		close(mockCNPResource.eventChan)
	}()

	// Run the controller
	err := pqc.Run(ctx)
	require.NoError(t, err)

	// Verify done callbacks were called
	<-done1
	<-done2
	<-doneSync

	counts := pqc.GetNamespacePolicyCounts()
	assert.Equal(t, 2, counts["default"], "expected 2 policies in default namespace after Run")
}

